firmware_template.source:
#include "http_ota.h"
#include <WiFi.h>
#include <WebServer.h>
#include <ElegantOTA.h>

static WebServer server(80);

void http_ota_setup(const char* ssid, const char* password) {
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  server.on("/", []() {
    server.send(200, "text/html", "<h1>Parakram OTA</h1><p>Go to <a href='/update'>/update</a></p>");
  });
  ElegantOTA.begin(&server);
  server.begin();
  Serial.printf("[http_ota] http://%s/update\n", WiFi.localIP().toString().c_str());
}

void http_ota_loop() {
  server.handleClient();
  ElegantOTA.loop();
}

String http_ota_get_url() {
  return "http://" + WiFi.localIP().toString() + "/update";
}
